#nullable enable // autogenerated

using MVZ2.GameContent.Contraptions;
using MVZ2.Vanilla.Audios;
using MVZ2Logic.Blueprints;
using MVZ2Logic.Definitions;
using MVZ2Logic.Entities;
using PVZEngine.Entities;
using PVZEngine.Level;
using PVZEngine.SeedPacks;

namespace MVZ2.GameContent.Seeds
{
    [AutoSeedOptionDefinition(VanillaBlueprintNames.heavyWeaponSpread)]
    public class HeavyWeaponSpread : SeedOptionDefinition
    {
        public HeavyWeaponSpread(string nsp, string name) : base(nsp, name)
        {
        }
        public override void Update(SeedPack seedPack, float rechargeSpeed)
        {
            base.Update(seedPack, rechargeSpeed);
            seedPack.SetProperty(EngineSeedProps.DISABLE_ID, IsValid(seedPack) ? null : LogicBlueprintErrors.invalid);
        }
        public override void Use(SeedPack seedPack)
        {
            base.Use(seedPack);
            Use(seedPack.Level);
        }
        public override void Use(LevelEngine level, SeedDefinition seedDef)
        {
            base.Use(level, seedDef);
            Use(level, seedDef);
        }
        private void Use(LevelEngine level)
        {
            var target = FindTargetEntity(level);
            if (target == null)
                return;
            Snipenser.UpgradeSpread(target);
            target.PlaySound(VanillaSoundID.gunReload);
        }
        private Entity? FindTargetEntity(LevelEngine level)
        {
            return level.FindFirstEntity(e => e.IsEntityOf(VanillaContraptionID.snipenser) && Snipenser.CanUpgradeSpread(e));
        }
        private bool IsValid(SeedPack seedPack)
        {
            var level = seedPack.Level;
            return FindTargetEntity(level) != null;
        }
    }
}
